SELECT id, order_id AS orderId, refund_type AS refundType, amount, status, idempotency_key AS idempotencyKey, retry_count AS retryCount, next_retry_time AS nextRetryTime, fail_reason AS failReason, create_time AS createTime, update_time AS updateTime FROM order_refund_task
AND order_id = #{orderId}
AND status = #{status}
